const RECIPIENT_IDS = ['996797292','813122587'];

const all           = $input.all().map(i => i.json);
const analyticsRows = all.filter(r => r.day   !== undefined && r.day   !== null);
const signupRows    = all.filter(r => r.signup_date !== undefined);

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0"/>
<title>MySquad Analytics</title>
<style>
:root{
  --a:#F13A01;--t:#111827;--m:#6B7280;--li:#D1D5DB;
  --bd:#E5E7EB;--bg:#F0F2F5;--s:#fff;--r:9px;
  --green:#10B981;--lw:210px;
}
*{box-sizing:border-box;margin:0;padding:0;}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;
  background:var(--bg);color:var(--t);min-height:100vh;}

/* ── Page shell ────────────────────────────────────────────────── */
.page{max-width:960px;margin:0 auto;padding:14px 12px 50px;}

/* Header */
.hdr{display:flex;align-items:center;gap:8px;margin-bottom:14px;}
.hdot{width:8px;height:8px;border-radius:50%;background:var(--a);flex-shrink:0;}
.hdr h1{font-size:16px;font-weight:800;letter-spacing:-.2px;}
.hdr .stamp{margin-left:auto;font-size:9px;color:var(--li);}

/* ── Two-column layout ─────────────────────────────────────────── */
.layout{display:flex;gap:12px;align-items:flex-start;}

/* LEFT SIDEBAR */
.sidebar{
  width:var(--lw);flex-shrink:0;
  display:flex;flex-direction:column;gap:10px;
  position:sticky;top:14px;
}

/* RIGHT MAIN */
.main{flex:1;min-width:0;display:flex;flex-direction:column;gap:12px;}

/* Mobile: stack */
@media(max-width:599px){
  .layout{flex-direction:column;}
  .sidebar{width:100%;position:static;}
}

/* ── Calendar (sidebar) ────────────────────────────────────────── */
.cal{background:var(--s);border:1px solid var(--bd);border-radius:var(--r);padding:8px;}
.cal-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:5px;}
.cal-mo{font-size:11px;font-weight:700;}
.cal-nav button{background:none;border:none;font-size:13px;font-weight:700;
  color:var(--m);cursor:pointer;padding:0 5px;border-radius:3px;line-height:1.6;}
.cal-nav button:hover:not(:disabled){color:var(--a);}
.cal-nav button:disabled{opacity:.2;cursor:not-allowed;}
.cal-dow{display:grid;grid-template-columns:repeat(7,1fr);margin-bottom:2px;}
.cal-dow span{text-align:center;font-size:8px;font-weight:600;color:var(--li);}
.cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:1px;}
.cc{height:22px;border-radius:3px;display:flex;align-items:center;
  justify-content:center;font-size:10px;color:var(--li);
  cursor:default;transition:all .1s;position:relative;}
.cc.om{opacity:0;}
.cc.hd{color:var(--t);font-weight:600;cursor:pointer;background:#FFF5F2;}
.cc.hd:hover{background:#FFE0D6;}
.cc.sel{background:var(--a)!important;color:#fff!important;font-weight:700;border-radius:4px;}
.cc.tod::after{content:'';position:absolute;bottom:1px;left:50%;
  transform:translateX(-50%);width:3px;height:3px;
  border-radius:50%;background:var(--a);}
.cc.sel.tod::after{background:rgba(255,255,255,.6);}

/* ── Owner roster (sidebar) ────────────────────────────────────── */
.roster{background:var(--s);border:1px solid var(--bd);border-radius:var(--r);overflow:hidden;}
.roster-hdr{padding:7px 10px;border-bottom:1px solid var(--bd);
  font-size:9px;font-weight:700;color:var(--a);
  text-transform:uppercase;letter-spacing:.7px;}
.roster-scroll{max-height:340px;overflow-y:auto;}
.rrow{display:flex;justify-content:space-between;align-items:center;
  padding:7px 10px;border-bottom:1px solid #F9FAFB;gap:6px;}
.rrow:last-child{border-bottom:none;}
.rname{font-size:11px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
.rbiz{font-size:9px;color:var(--m);margin-top:1px;
  white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:110px;}
.rbal{font-size:11px;font-weight:800;flex-shrink:0;}
.rbal.ok{color:var(--green);}
.rbal.low{color:var(--a);}

/* ── Day label ─────────────────────────────────────────────────── */
.dlbl{font-size:14px;font-weight:800;color:var(--t);}
.dlbl span{font-size:11px;font-weight:400;color:var(--m);margin-left:6px;}

/* ── KPIs ──────────────────────────────────────────────────────── */
.kpis{display:grid;grid-template-columns:repeat(2,1fr);gap:7px;}
@media(min-width:480px){.kpis{grid-template-columns:repeat(4,1fr);}}
.kpi{background:var(--s);border:1px solid var(--bd);border-radius:var(--r);padding:10px 11px;}
.kl{font-size:8px;font-weight:700;color:var(--m);text-transform:uppercase;
  letter-spacing:.4px;margin-bottom:3px;}
.kv{font-size:22px;font-weight:800;line-height:1;}
.ks{font-size:9px;color:var(--m);margin-top:2px;}

/* ── Section label ─────────────────────────────────────────────── */
.slbl{font-size:9px;font-weight:700;color:var(--a);text-transform:uppercase;
  letter-spacing:.7px;border-bottom:1px solid var(--bd);padding-bottom:5px;}

/* ── Feature breakdown bars ────────────────────────────────────── */
.ovr{display:flex;flex-direction:column;gap:6px;}
.or{background:var(--s);border:1px solid var(--bd);border-radius:7px;padding:9px 11px;}
.om2{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:4px;}
.on{font-size:12px;font-weight:600;display:flex;align-items:center;gap:5px;}
.opip{width:6px;height:6px;border-radius:50%;flex-shrink:0;}
.ostat b{font-size:13px;font-weight:800;color:var(--t);}
.ostat{font-size:11px;color:var(--m);}
.bt{height:5px;background:#F3F4F6;border-radius:3px;overflow:hidden;}
.bf{height:100%;border-radius:3px;transition:width .3s;}

/* ── Tenant activity cards ─────────────────────────────────────── */
.cards{display:flex;flex-direction:column;gap:6px;}
.card{background:var(--s);border:1px solid var(--bd);border-radius:var(--r);overflow:hidden;}
.ctrig{display:flex;justify-content:space-between;align-items:center;
  padding:10px 12px;cursor:pointer;user-select:none;transition:background .1s;}
.ctrig:hover{background:#FAFAFA;}
.cname{font-size:13px;font-weight:800;}
.ctags{display:flex;align-items:center;gap:4px;margin-top:2px;flex-wrap:wrap;}
.ctag{font-size:9px;font-weight:600;color:var(--m);background:#F3F4F6;
  border-radius:3px;padding:1px 5px;}
.ctag.sp{color:var(--a);background:#FFF5F2;}
.cright{display:flex;align-items:center;gap:7px;flex-shrink:0;margin-left:8px;}
.cevt{font-size:15px;font-weight:800;color:var(--a);}
.cevtl{font-size:9px;color:var(--m);text-align:right;}
.chev{font-size:9px;color:var(--li);transition:transform .2s;}
.card.open .chev{transform:rotate(180deg);}
.cbody{display:none;border-top:1px solid var(--bd);}
.card.open .cbody{display:block;}
.bsec{padding:9px 12px;border-bottom:1px solid #F9FAFB;}
.bsec:last-child{border-bottom:none;}
.bsnm{font-size:9px;font-weight:700;color:var(--m);text-transform:uppercase;
  letter-spacing:.5px;margin-bottom:6px;display:flex;justify-content:space-between;}
.bsnm span{font-weight:400;text-transform:none;letter-spacing:0;color:var(--li);}
.feats{display:flex;flex-direction:column;gap:5px;}
.fr{display:grid;grid-template-columns:1fr 38px 55px;align-items:center;gap:5px;}
.fn{font-size:11px;}
.fp{font-size:11px;font-weight:700;text-align:right;}
.fb2{height:4px;background:#F3F4F6;border-radius:2px;overflow:hidden;}
.ff{height:100%;border-radius:2px;}
.fz .fn{color:var(--li);}
.fz .fp{color:var(--li);font-weight:400;}
.noact{color:var(--li);font-size:10px;font-style:italic;}
.empty{background:var(--s);border:1px solid var(--bd);border-radius:var(--r);
  padding:24px;text-align:center;color:var(--m);font-size:12px;}
</style>
</head>
<body>
<div class="page">

  <!-- Header -->
  <div class="hdr">
    <div class="hdot"></div>
    <h1>MySquad Analytics</h1>
    <div class="stamp" id="stamp"></div>
  </div>

  <div class="layout">

    <!-- ── LEFT SIDEBAR ── -->
    <div class="sidebar">

      <!-- Calendar -->
      <div class="cal">
        <div class="cal-top">
          <div class="cal-mo" id="calmo"></div>
          <div class="cal-nav">
            <button id="cprev" onclick="calShift(-1)">‹</button>
            <button id="cnext" onclick="calShift(1)">›</button>
          </div>
        </div>
        <div class="cal-dow">
          <span>S</span><span>M</span><span>T</span><span>W</span>
          <span>T</span><span>F</span><span>S</span>
        </div>
        <div class="cal-grid" id="calgrid"></div>
      </div>

      <!-- Owner roster — ALL owners, current balances -->
      <div class="roster">
        <div class="roster-hdr">All Owners · Current Balance</div>
        <div class="roster-scroll" id="roster"></div>
      </div>

    </div><!-- /sidebar -->

    <!-- ── RIGHT MAIN ── -->
    <div class="main">

      <div class="dlbl" id="dlbl"></div>
      <div class="kpis" id="kpis"></div>

      <div class="slbl">Feature Activity Breakdown</div>
      <div class="ovr" id="ovr"></div>

      <div class="slbl">Owner Activity This Day</div>
      <div class="cards" id="cards"></div>

    </div><!-- /main -->

  </div><!-- /layout -->
</div><!-- /page -->

<script>
const RAW     = ANALYTICS_DATA_PLACEHOLDER;
const SIGNUPS = SIGNUPS_DATA_PLACEHOLDER;

const F=[
  {k:'google',   l:'Google Actions',  c:'#4285F4'},
  {k:'media',    l:'Media Generation',c:'#F13A01'},
  {k:'orders',   l:'Order Management',c:'#10B981'},
  {k:'dispatch', l:'Dispatch',        c:'#06B6D4'},
  {k:'followups',l:'Lead Follow-Ups', c:'#8B5CF6'},
  {k:'reminders',l:'Reminder Alerts', c:'#F59E0B'},
];
const MO=['January','February','March','April','May','June',
          'July','August','September','October','November','December'];

// ── Index RAW by day ────────────────────────────────────────────
const dayData={};
RAW.forEach(r=>{if(!dayData[r.day])dayData[r.day]=[];dayData[r.day].push(r);});

// ── Build roster from table_19 (all tenants, not just active) ────
function firstName(n){return(n||'').split(' ')[0]||n||'?';}

function buildRoster(){
  const sorted=[...SIGNUPS].sort((a,b)=>
    (a.full_name||'').localeCompare(b.full_name||''));
  document.getElementById('roster').innerHTML=sorted.map(s=>{
    const bal=+s.credits_balance||0;
    const name=firstName(s.preferred_name||s.full_name);
    return\`<div class="rrow">
      <div style="min-width:0">
        <div class="rname">\${name}</div>
        <div class="rbiz">\${s.business_names||'—'}</div>
      </div>
      <div class="rbal \${bal>0?'ok':'low'}">₦\${bal.toLocaleString()}</div>
    </div>\`;
  }).join('');
}

// ── Calendar state ──────────────────────────────────────────────
const allDays=Object.keys(dayData).sort().reverse();
function lagosToday(){return new Date(Date.now()+3600000).toISOString().split('T')[0];}
let cur=lagosToday();
if(!dayData[cur]&&allDays.length>0)cur=allDays[0];
let calY,calM;
function initCal(){const p=cur.split('-');calY=+p[0];calM=+p[1]-1;}
initCal();

function buildCal(){
  document.getElementById('calmo').textContent=MO[calM]+' '+calY;
  const tod=lagosToday();
  const minDay=allDays[allDays.length-1]||tod;
  const minP=minDay.split('-'),todP=tod.split('-');
  const pm=calM===0?11:calM-1,py=calM===0?calY-1:calY;
  const nm=calM===11?0:calM+1,ny=calM===11?calY+1:calY;
  document.getElementById('cprev').disabled=
    py<+minP[0]||(py===+minP[0]&&pm<+minP[1]-1);
  document.getElementById('cnext').disabled=
    ny>+todP[0]||(ny===+todP[0]&&nm>+todP[1]-1);

  const fd=new Date(calY,calM,1).getDay();
  const dim=new Date(calY,calM+1,0).getDate();
  const dip=new Date(calY,calM,0).getDate();
  const g=document.getElementById('calgrid');
  g.innerHTML='';
  const total=fd+dim>35?42:35;
  for(let i=0;i<total;i++){
    const el=document.createElement('div');el.className='cc';
    let dn,ds,inM;
    if(i<fd){
      dn=dip-fd+i+1;
      const m2=calM===0?12:calM,y2=calM===0?calY-1:calY;
      ds=\`\${y2}-\${String(m2).padStart(2,'0')}-\${String(dn).padStart(2,'0')}\`;
      inM=false;el.classList.add('om');
    }else if(i>=fd+dim){
      dn=i-fd-dim+1;
      const m2=calM===11?1:calM+2,y2=calM===11?calY+1:calY;
      ds=\`\${y2}-\${String(m2).padStart(2,'0')}-\${String(dn).padStart(2,'0')}\`;
      inM=false;el.classList.add('om');
    }else{
      dn=i-fd+1;
      ds=\`\${calY}-\${String(calM+1).padStart(2,'0')}-\${String(dn).padStart(2,'0')}\`;
      inM=true;
    }
    el.textContent=dn;
    if(ds===tod&&inM)el.classList.add('tod');
    if(ds===cur)el.classList.add('sel');
    if(dayData[ds]){el.classList.add('hd');el.onclick=(()=>{const d=ds;return()=>pick(d);})();}
    g.appendChild(el);
  }
}

function calShift(d){
  calM+=d;if(calM>11){calM=0;calY++;}if(calM<0){calM=11;calY--;}buildCal();
}
function pick(ds){
  cur=ds;const p=ds.split('-');calY=+p[0];calM=+p[1]-1;buildCal();renderDay();
}

function fmtDay(ds){
  const d=new Date(ds+'T12:00:00Z');
  return d.toLocaleDateString('en-NG',{weekday:'short',day:'numeric',month:'short',year:'numeric'});
}
function rowTot(r){return F.reduce((s,f)=>s+(+r[f.k]||0),0);}
function modeLabel(m){
  return{product_only:'Products',service_only:'Services',
    hybrid_product_led:'Hybrid',hybrid_service_led:'Hybrid'}[m]||'';
}

function renderDay(){
  const tod=lagosToday();
  const isToday=cur===tod;
  document.getElementById('dlbl').innerHTML=
    \`\${fmtDay(cur)}\${isToday?'<span>· Today</span>':''}\`;

  const rows=dayData[cur]||[];
  const signupCount=SIGNUPS.filter(s=>s.signup_date<=cur).length;

  if(rows.length===0){
    document.getElementById('kpis').innerHTML=\`
      <div class="kpi"><div class="kl">Total Users</div>
        <div class="kv">\${signupCount}</div><div class="ks">signed up by this date</div></div>
      <div class="kpi"><div class="kl">Active Owners</div>
        <div class="kv">0</div><div class="ks">this day</div></div>
      <div class="kpi"><div class="kl">Events</div>
        <div class="kv">0</div><div class="ks">no activity</div></div>
      <div class="kpi"><div class="kl">Top Feature</div>
        <div class="kv" style="font-size:11px;padding-top:4px">—</div>
        <div class="ks">&nbsp;</div></div>\`;
    document.getElementById('ovr').innerHTML=
      '<div class="empty">No feature activity recorded for this day.</div>';
    document.getElementById('cards').innerHTML='';
    return;
  }

  const grand=rows.reduce((s,r)=>s+rowTot(r),0);
  const activeT=[...new Set(rows.map(r=>r.tenant_id))].length;
  const topF=F.map(f=>({...f,t:rows.reduce((s,r)=>s+(+r[f.k]||0),0)}))
    .sort((a,b)=>b.t-a.t)[0];
  const topPct=grand>0?((topF.t/grand)*100).toFixed(1):'—';

  document.getElementById('kpis').innerHTML=\`
    <div class="kpi"><div class="kl">Total Users</div>
      <div class="kv">\${signupCount}</div><div class="ks">signed up by this date</div></div>
    <div class="kpi"><div class="kl">Active Owners</div>
      <div class="kv">\${activeT}</div><div class="ks">this day</div></div>
    <div class="kpi"><div class="kl">Total Events</div>
      <div class="kv">\${grand.toLocaleString()}</div><div class="ks">all features</div></div>
    <div class="kpi"><div class="kl">Top Feature</div>
      <div class="kv" style="font-size:11px;padding-top:4px;line-height:1.2">\${topF.l}</div>
      <div class="ks">\${topPct}% of activity</div></div>
  \`;

  // Feature bars
  const ovr=F.map(f=>({...f,t:rows.reduce((s,r)=>s+(+r[f.k]||0),0)}))
    .sort((a,b)=>b.t-a.t);
  const maxT=Math.max(...ovr.map(f=>f.t),1);
  document.getElementById('ovr').innerHTML=ovr.map(f=>{
    const pct=grand>0?((f.t/grand)*100).toFixed(1):'0.0';
    const bw=((f.t/maxT)*100).toFixed(1);
    return\`<div class="or">
      <div class="om2">
        <span class="on"><span class="opip" style="background:\${f.c}"></span>\${f.l}</span>
        <span class="ostat"><b>\${pct}%</b>&nbsp;\${f.t.toLocaleString()} events</span>
      </div>
      <div class="bt"><div class="bf" style="width:\${bw}%;background:\${f.c}"></div></div>
    </div>\`;
  }).join('');

  // Tenant cards
  const byT={};
  rows.forEach(r=>{
    if(!byT[r.tenant_id]){
      byT[r.tenant_id]={
        name:firstName(r.preferred_name||r.full_name||'?'),
        dailySpend:0,businesses:[]
      };
    }
    byT[r.tenant_id].dailySpend+=(+r.daily_credits_spent||0);
    byT[r.tenant_id].businesses.push(r);
  });

  const tList=Object.entries(byT)
    .map(([tid,td])=>({tid,...td,
      totalEvt:td.businesses.reduce((s,r)=>s+rowTot(r),0)}))
    .sort((a,b)=>b.totalEvt-a.totalEvt);

  document.getElementById('cards').innerHTML=tList.map((tn,idx)=>{
    const bizCount=tn.businesses.length;
    const bizLabel=bizCount===1?'1 business':\`\${bizCount} businesses\`;
    const bizSecs=tn.businesses.map(r=>{
      const t2=rowTot(r);
      const ml=modeLabel(r.business_mode);
      const feats=F.map(f=>({...f,cnt:+r[f.k]||0,
        pct:t2>0?((+r[f.k]||0)/t2)*100:0}))
        .sort((a,b)=>b.cnt-a.cnt);
      return\`<div class="bsec">
        <div class="bsnm">\${r.business_name}\${ml?\` · \${ml}\`:''}
          <span>\${t2} events</span></div>
        \${t2===0?'<div class="noact">No activity this day</div>'
          :\`<div class="feats">\${feats.map(f=>\`
            <div class="fr \${f.cnt===0?'fz':''}">
              <span class="fn">\${f.l}</span>
              <span class="fp" style="\${f.cnt>0?'color:'+f.c:''}">\${f.pct>0?f.pct.toFixed(1)+'%':'—'}</span>
              <div class="fb2"><div class="ff" style="width:\${f.pct.toFixed(1)}%;background:\${f.c}"></div></div>
            </div>\`).join('')}</div>\`}
      </div>\`;
    }).join('');

    return\`<div class="card" id="tc\${idx}">
      <div class="ctrig" onclick="tog(\${idx})">
        <div style="flex:1;min-width:0">
          <div class="cname">\${tn.name}</div>
          <div class="ctags">
            <span class="ctag">\${bizLabel}</span>
            \${tn.dailySpend>0
              ?\`<span class="ctag sp">₦\${tn.dailySpend.toLocaleString()} spent</span>\`:''}
          </div>
        </div>
        <div class="cright">
          <div>
            <div class="cevt">\${tn.totalEvt}</div>
            <div class="cevtl">events</div>
          </div>
          <span class="chev">▼</span>
        </div>
      </div>
      <div class="cbody">\${bizSecs}</div>
    </div>\`;
  }).join('');
}

function tog(i){document.getElementById('tc'+i).classList.toggle('open');}

// ── Init ────────────────────────────────────────────────────────
const ln=new Date(Date.now()+3600000);
document.getElementById('stamp').textContent=
  ln.toISOString().replace('T',' ').substring(0,16)+' WAT';
buildRoster();
buildCal();
renderDay();
</script>
</body>
</html>
`
  .replace('ANALYTICS_DATA_PLACEHOLDER', JSON.stringify(analyticsRows))
  .replace('SIGNUPS_DATA_PLACEHOLDER',   JSON.stringify(signupRows));

const now = new Date(Date.now() + 3600000);
const ds  = now.toISOString().split('T')[0];
const ts  = now.toISOString().replace('T',' ').substring(0,16);

return [{json:{
  html,
  filename: `mysquad_analytics_${ds}.html`,
  recipient_ids: RECIPIENT_IDS,
  analytics_rows: analyticsRows.length,
  signup_rows:    signupRows.length,
  unique_days:   [...new Set(analyticsRows.map(r=>r.day))].length,
  generated_at:  ts+' WAT'
}}];

const data = $input.first().json;
const base64 = Buffer.from(data.html, 'utf8').toString('base64');
return [{
  json: {
    recipient_ids: data.recipient_ids,
    filename:      data.filename,
    generated_at:  data.generated_at,
    row_count:     data.row_count,
    unique_days:   data.unique_days
  },
  binary: {
    document: {
      data:          base64,
      mimeType:      'text/html',
      fileName:      data.filename,
      fileExtension: 'html'
    }
  }
}];

const data = $input.first();
return (data.json.recipient_ids || []).map(chatId => ({
  json: {
    chat_id:      chatId,
    filename:     data.json.filename,
    generated_at: data.json.generated_at,
    row_count:    data.json.row_count,
    unique_days:  data.json.unique_days
  },
  binary: data.binary
}));
